def _parse_blender_env(path):
    env = {}
    if not path or not os.path.isfile(path):
        return env
    with open(path, 'r') as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith('#'):
                continue
            if '=' in line:
                key, val = line.split('=', 1)
                env[key.strip()] = val.strip()
    return env

def _parse_bat_env(path):
    env = {}
    if not path or not os.path.isfile(path):
        return env
    with open(path, 'r') as f:
        for line in f:
            line = line.strip()
            lower = line.lower()
            if lower.startswith('set ') and '=' in line:
                rest = line[4:]
                key, val = rest.split('=', 1)
                env[key.strip()] = val.strip()
    return env

def _build_env(bat_file, blender_env_file):
    env = os.environ.copy()
    blender_vars = _parse_blender_env(blender_env_file)
    bat_vars = _parse_bat_env(bat_file)
    for k, v in blender_vars.items():
        for ek, ev in env.items():
            v = v.replace(f'%{ek}%', ev)
        env[k] = v
    for k, v in bat_vars.items():
        for ek, ev in env.items():
            v = v.replace(f'%{ek}%', ev)
        env[k] = v
    return env

async def on_parameter_changed(self, name, value):
    if name == 'blender_version' and value in VERSION_PATHS:
        self.set_parameter('blender.exe', VERSION_PATHS[value])

def _fail(self, msg):
    return {'success': False, 'stdout': '', 'stderr': msg, 'exit_code': -1, 'executed_actions': [], 'skipped_actions': []}

async def _set_outputs(self, result):
    for k, v in result.items():
        await self.set_output(k, v)
    await self.set_output('exec_out', True)

async def execute(self, inputs):
    version = inputs.get('blender_version') or self.get_parameter('blender_version', '4.2')
    blender_exe = inputs.get('blender.exe') or self.get_parameter('blender.exe', '')
    if not blender_exe and version in VERSION_PATHS:
        blender_exe = VERSION_PATHS[version]
    bat_file = inputs.get('bat_file') or self.get_parameter('bat_file', '')
    blender_env_file = inputs.get('blender_env_file') or self.get_parameter('blender_env_file', '')
    blend_file = inputs.get('blend_file') or self.get_parameter('blend_file', '')
    actions = inputs.get('actions') or []

    if not isinstance(actions, list):
        actions = [actions]

    env = _build_env(bat_file, blender_env_file)
    env_sources = []
    if bat_file:
        env_sources.append(f'bat: {bat_file}')
    if blender_env_file:
        env_sources.append(f'blender.env: {blender_env_file}')
    if env_sources:
        self.log_info(f'Environment loaded from: {" + ".join(env_sources)}')

    # Validate actions
    planned = []
    skipped = []
    REQUIRES_PATH = {
        'open_blend': 'blend_path', 'save_blend': 'blend_path',
        'import_obj': 'obj_path', 'import_fbx': 'fbx_path',
        'import_alembic': 'abc_path', 'import_gltf': 'gltf_path',
        'export_obj': 'obj_path', 'export_fbx': 'fbx_path',
        'export_alembic': 'abc_path', 'export_gltf': 'gltf_path',
        'export_usd': 'usd_path', 'render': 'output_path',
    }
    for action in actions:
        if not isinstance(action, dict):
            skipped.append({'action': action, 'reason': 'not a dict'})
            continue
        action_type = action.get('type', '')
        required_field = REQUIRES_PATH.get(action_type)
        if required_field and not action.get(required_field):
            skipped.append({'action': action, 'reason': f'{required_field} is empty'})
            continue
        if action_type == 'custom_python' and not action.get('python_code'):
            skipped.append({'action': action, 'reason': 'python_code is empty'})
            continue
        if action_type == 'bake_animation':
            planned.append(action)
            continue
        KNOWN = {
            'open_blend', 'save_blend', 'new_blend', 'scene_info', 'set_frame_range',
            'import_obj', 'import_fbx', 'import_alembic', 'import_gltf',
            'export_obj', 'export_fbx', 'export_alembic', 'export_gltf', 'export_usd',
            'set_render_settings', 'render', 'bake_animation', 'custom_python'
        }
        if action_type not in KNOWN:
            skipped.append({'action': action, 'reason': f'unknown action type: {action_type}'})
            continue
        planned.append(action)

    if skipped:
        for s in skipped:
            self.log_error(f'Action skipped: {s["reason"]}')
        result = _fail(self, f'{len(skipped)} action(s) skipped due to validation errors')
        result['skipped_actions'] = skipped
        await _set_outputs(self, result)
        return result

    payload = {'blend_file': blend_file, 'actions': planned}
    payload_file = tempfile.NamedTemporaryFile(mode='w', suffix='.json', delete=False)
    script_file = tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False)
    results_file = tempfile.NamedTemporaryFile(mode='w', suffix='_results.json', delete=False)
    results_file.close()
    try:
        json.dump(payload, payload_file)
        payload_file.close()
        script_file.write(BLENDER_RUNNER_SCRIPT)
        script_file.close()

        # Build Blender command: blender --background [blend] --python runner.py -- payload results
        cmd = [blender_exe, '--background']
        # Note: blend_file is already handled inside the runner via payload,
        # but we don't pre-open it here to keep the runner in full control.
        cmd += ['--python', script_file.name, '--', payload_file.name, results_file.name]

        self.log_info(f'Running Blender {version}: {" ".join(cmd)}')

        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=600, env=env)

        executed = []
        blender_errors = []
        try:
            with open(results_file.name, 'r') as rf:
                bl_results = json.load(rf)
            for ar in bl_results.get('actions', []):
                if ar.get('ok'):
                    merged = dict(planned[ar['index']])
                    if 'info' in ar:
                        merged['info'] = ar['info']
                    executed.append(merged)
                else:
                    blender_errors.append(f'Action {ar["index"]} ({ar["type"]}): {ar["error"]}')
            blender_errors.extend(bl_results.get('errors', []))
        except Exception:
            pass

        ok = proc.returncode == 0 and not blender_errors

        if proc.returncode != 0 and not blender_errors and proc.stderr:
            blender_errors.append(f'Blender process failed with exit code {proc.returncode}')

        for err in blender_errors:
            self.log_error(err)

        result = {
            'success': ok,
            'stdout': proc.stdout,
            'stderr': proc.stderr,
            'exit_code': proc.returncode,
            'executed_actions': executed,
            'skipped_actions': [],
        }
        await _set_outputs(self, result)

        if ok:
            self.log_info(f'Blender completed successfully. {len(executed)} actions executed.')
        else:
            self.log_error(f'Blender run failed. {len(executed)}/{len(planned)} actions succeeded.')

        return result
    except Exception as e:
        self.log_error(f'Blender execution failed: {e}')
        result = _fail(self, str(e))
        await _set_outputs(self, result)
        return result
    finally:
        for f in [payload_file.name, script_file.name, results_file.name]:
            try:
                os.unlink(f)
            except Exception:
                pass
